147. 	if !ok {
148. 		return fmt.Errorf("unknown agent for program %q", program)
149. 	}
150. 	r, _ := recorderFor(tool)
151. 	if agentSessionID == "" {
152. 		return fmt.Errorf("agent %q has no restorable transcript path", tool)
