200. 	var tools []string
201. 	for _, a := range agent.Agents {
202. 		if a.RecorderTool == "" {
203. 			continue
204. 		}
205. 		if _, err := exec.LookPath(a.Exe); err == nil {
206. 			tools = append(tools, a.RecorderTool)
