226. 	exe, err := executablePath()
227. 	if err != nil {
228. 		return nil, err
229. 	}
230. 	tools := detectAgents()
231. 	if len(tools) == 0 {
232. 		return nil, nil
233. 	}
234. 	for _, tool := range tools {
235. 		if err := InstallHooks(dir, tool, exe); err != nil {
236. 			return nil, fmt.Errorf("%s: %w", tool, err)
237. 		}
238. 	}
239. 	return tools, nil
240. }
