264. // agentHome resolves an agent's data directory: envKey when set (and
265. // non-empty), else homeSub under the user's home directory.
266. func agentHome(envKey, homeSub string) string {
267. 	if envKey != "" {
268. 		if v := os.Getenv(envKey); v != "" {
269. 			return v
270. 		}
271. 	}
272. 	home, err := os.UserHomeDir()
273. 	if err != nil {
274. 		return homeSub
275. 	}
276. 	return filepath.Join(home, homeSub)
277. }
