279. // sanitizePath mirrors the path munging Claude Code and Cursor use for their
280. // per-project transcript directories: every non-alphanumeric byte becomes
281. // a dash.
282. func sanitizePath(p string) string {
283. 	return strings.Map(func(r rune) rune {
284. 		switch {
285. 		case r >= 'a' && r <= 'z', r >= 'A' && r <= 'Z', r >= '0' && r <= '9':
286. 			return r
287. 		}
288. 		return '-'
289. 	}, p)
290. }
291. 
292. func existing(path string) string {
293. 	if _, err := os.Stat(path); err != nil {
294. 		return ""
295. 	}
296. 	return path
297. }
298.

