 		}
 		if a.RecorderTool != r.Tool() {
 			t.Errorf(
 				"agent %q declares RecorderTool %q, but its recorder's Tool() = %q",
 				a.Exe, a.RecorderTool, r.Tool(),
 			)
 		}
