86. 	var l struct {
87. 		Timestamp string          `json:"timestamp"`
88. 		Type      string          `json:"type"`
89. 		Payload   json.RawMessage `json:"payload"`
90. 	}
91. 	if json.Unmarshal(line, &l) != nil {
92. 		return "", "", time.Time{}
93. 	}
