95. 	if l.Type != "response_item" {
96. 		return "", "", ts
97. 	}
98. 	var p struct {
99. 		Type    string `json:"type"`
100. 		Role    string `json:"role"`
101. 		Content []struct {
102. 			Type string `json:"type"`
103. 			Text string `json:"text"`
104. 		} `json:"content"`
105. 	}
106. 	if json.Unmarshal(l.Payload, &p) != nil || p.Type != "message" {
107. 		return "", "", ts
108. 	}
109. 	if p.Role != "user" && p.Role != "assistant" {
110. 		return "", "", ts
111. 	}
112. 	var b strings.Builder
113. 	for _, blk := range p.Content {
114. 		if blk.Type != "input_text" && blk.Type != "output_text" &&
115. 			blk.Type != "text" {
116. 			continue
117. 		}
118. 		if p.Role == "user" && isCodexSystemContent(blk.Text) {
119. 			continue
120. 		}
121. 		b.WriteString(blk.Text)
122. 	}
123. 	return p.Role, b.String(), ts
124. }
