127. // injects rather than a typed prompt, mirroring the blocks the reference
128. // importer drops.
129. func isCodexSystemContent(text string) bool {
130. 	t := strings.TrimSpace(text)
131. 	for _, p := range []string{
132. 		"<environment_context>", "<permissions", "# AGENTS.md",
133. 		"<user_instructions>",
134. 	} {
135. 		if strings.HasPrefix(t, p) {
136. 			return true
137. 		}
138. 	}
139. 	return false
