11. // baseExe reduces a launch program ("/usr/bin/claude --resume") to its base
12. // executable name ("claude"). It mirrors sessionstatus.toolName so the program
13. // picker and the agent registry agree on "the agent" even when the field
14. // already carries flags.
15. func baseExe(program string) string {
16. 	program = strings.TrimSpace(program)
17. 	if program == "" {
18. 		return ""
19. 	}
20. 	return filepath.Base(strings.Fields(program)[0])
21. }
22. 
23. // AutonomousFlag returns the canonical skip-permissions flag for program's base
24. // executable and whether one is known. A shell or unknown program has no flag.
25. func AutonomousFlag(program string) (string, bool) {
26. 	a, ok := agent.ByExe(baseExe(program))
27. 	if !ok || a.Autonomy == nil {
28. 		return "", false
29. 	}
30. 	return a.Autonomy.Flag, true
31. }
32. 
33. // AutonomousAvailable reports whether program maps to a known autonomous flag. It
34. // drives the create form's toggle: enabled only when a flag exists to append.
35. func AutonomousAvailable(program string) bool {
36. 	a, ok := agent.ByExe(baseExe(program))
37. 	return ok && a.Autonomy != nil
38. }
39. 
40. // WithAutonomous returns program with its agent's skip-permissions flag appended.
41. // It returns program unchanged when no flag is known for the agent, or when the
42. // program already carries the canonical flag or one of its aliases — so toggling
43. // autonomous on is idempotent and never stacks conflicting flags onto a command
44. // the user already wrote by hand.
45. func WithAutonomous(program string) string {
46. 	a, ok := agent.ByExe(baseExe(program))
47. 	if !ok || a.Autonomy == nil {
48. 		return program
49. 	}
50. 	tokens := strings.Fields(program)
51. 	if slices.Contains(tokens, a.Autonomy.Flag) {
52. 		return program
53. 	}
54. 	for _, alias := range a.Autonomy.Aliases {
55. 		if slices.Contains(tokens, alias) {
56. 			return program
57. 		}
58. 	}
59. 	return strings.TrimSpace(program) + " " + a.Autonomy.Flag
60. }
