1. package record
2. 
3. import (
4. 	"bufio"
5. 	"bytes"
6. 	"encoding/json"
7. 	"regexp"
8. 	"strings"
9. 	"time"
10. )
11. 
12. // maxTranscriptLine bounds a single transcript line; agent transcripts carry
13. // whole tool results on one line, which can be large.
14. const maxTranscriptLine = 16 << 20
15. 
16. // Message is one turn of a session in the common shape every agent's native
17. // transcript is normalized into, so read-back commands and future consumers
18. // never branch per agent. Role and Content are the minimum; Timestamp is set
19. // when the native format carries one; Raw preserves the original native line
20. // so the transcript can be rendered richly and, for line-based formats,
21. // reconstructed losslessly for a native resume.
22. type Message struct {
23. 	Role      string          `json:"role"`
24. 	Content   string          `json:"content"`
25. 	Timestamp time.Time       `json:"timestamp,omitzero"`
26. 	Raw       json.RawMessage `json:"raw,omitempty"`
27. }
28. 
29. // lineParser reads one native transcript line into the fields of a Message.
30. // A line it does not recognize (a header, a tool result, plumbing) yields an
31. // empty role, so it is preserved as raw context but never shown as a turn.
32. type lineParser func(line []byte) (role, content string, ts time.Time)
33. 
34. // normalize converts an agent's native transcript to the stored normalized
35. // JSONL. An unknown agent or a transcript the agent's parser makes nothing of
36. // is returned unchanged, so a checkpoint still carries what was captured and
37. // the missing-normalization is a display gap, never a lost transcript.
38. func normalize(tool string, native []byte) []byte {
39. 	if len(native) == 0 {
40. 		return nil
41. 	}
42. 	r, ok := recorderFor(tool)
43. 	if !ok {
44. 		return native
45. 	}
46. 	msgs := r.Normalize(native)
47. 	if len(msgs) == 0 {
48. 		return native
49. 	}
50. 	var b bytes.Buffer
51. 	enc := json.NewEncoder(&b)
52. 	enc.SetEscapeHTML(false)
53. 	for _, m := range msgs {
54. 		if err := enc.Encode(m); err != nil {
55. 			continue
56. 		}
57. 	}
58. 	return b.Bytes()
59. }
60. 
61. // normalizeJSONL builds the normalized messages for a line-based (JSONL)
62. // transcript: one Message per non-blank line, in order, each carrying its raw
63. // bytes, with role/content/timestamp filled by parse. Preserving every line
64. // (even ones parse does not recognize) keeps the transcript reconstructible.
65. func normalizeJSONL(native []byte, parse lineParser) []Message {
66. 	var msgs []Message
67. 	sc := bufio.NewScanner(bytes.NewReader(native))
68. 	sc.Buffer(make([]byte, 0, 64<<10), maxTranscriptLine)
69. 	for sc.Scan() {
70. 		line := bytes.TrimSpace(sc.Bytes())
71. 		if len(line) == 0 {
72. 			continue
73. 		}
74. 		var role, content string
75. 		var ts time.Time
76. 		if parse != nil {
77. 			role, content, ts = parse(line)
78. 		}
79. 		msgs = append(msgs, Message{
80. 			Role: role, Content: content, Timestamp: ts, Raw: rawJSON(line),
81. 		})
82. 	}
83. 	return msgs
84. }
85. 
86. // rawJSON keeps a native line as a valid JSON value for the Message.Raw field:
87. // the line itself when it is valid JSON, else the line as a JSON string so a
88. // truncated or non-JSON line still round-trips through the store.
89. func rawJSON(line []byte) json.RawMessage {
90. 	if json.Valid(line) {
91. 		return json.RawMessage(append([]byte(nil), line...))
92. 	}
93. 	b, _ := json.Marshal(string(line))
94. 	return b
95. }
96. 
97. // denormalize reconstructs the native transcript bytes from stored normalized
98. // JSONL by concatenating each message's raw line, so a native resume finds the
99. // agent's own format. Data that is not in the normalized shape (a checkpoint
100. // written before normalization, stored raw) is returned unchanged.
101. func denormalize(data []byte) []byte {
102. 	if !looksNormalized(data) {
103. 		return data
104. 	}
105. 	var b bytes.Buffer
106. 	sc := bufio.NewScanner(bytes.NewReader(data))
107. 	sc.Buffer(make([]byte, 0, 64<<10), maxTranscriptLine)
108. 	for sc.Scan() {
109. 		line := bytes.TrimSpace(sc.Bytes())
110. 		if len(line) == 0 {
111. 			continue
112. 		}
113. 		var m Message
114. 		if json.Unmarshal(line, &m) != nil || len(m.Raw) == 0 {
115. 			continue
116. 		}
117. 		raw := bytes.TrimSpace(m.Raw)
118. 		if len(raw) > 0 && raw[0] == '"' {
119. 			var s string
120. 			if json.Unmarshal(raw, &s) == nil {
121. 				b.WriteString(s)
122. 				b.WriteByte('\n')
123. 				continue
124. 			}
125. 		}
126. 		b.Write(raw)
127. 		b.WriteByte('\n')
128. 	}
129. 	return b.Bytes()
130. }
131. 
132. // looksNormalized reports whether data is stored normalized JSONL rather than
133. // a raw native transcript, by the presence of the raw field on the first line.
134. // No native transcript carries a top-level "raw", so this never misfires.
135. func looksNormalized(data []byte) bool {
136. 	sc := bufio.NewScanner(bytes.NewReader(data))
137. 	sc.Buffer(make([]byte, 0, 64<<10), maxTranscriptLine)
138. 	for sc.Scan() {
139. 		line := bytes.TrimSpace(sc.Bytes())
140. 		if len(line) == 0 {
141. 			continue
142. 		}
143. 		var m map[string]json.RawMessage
144. 		if json.Unmarshal(line, &m) != nil {
145. 			return false
146. 		}
147. 		_, ok := m["raw"]
148. 		return ok
149. 	}
150. 	return false
151. }
152. 
153. // firstUserIntent returns the first real user prompt from normalized messages:
154. // the intent that started the session. Wrapper/plumbing turns and injected
155. // context are skipped, matching the Claude-native extractor's behavior so every
156. // agent's intent reads as what the human typed.
157. func firstUserIntent(msgs []Message) string {
158. 	for _, m := range msgs {
159. 		if m.Role != "user" {
160. 			continue
161. 		}
162. 		text := strings.TrimSpace(m.Content)
163. 		if text == "" || isWrapper(text) {
164. 			continue
165. 		}
166. 		if text = sanitizeIntent(text); text != "" {
167. 			return text
168. 		}
169. 	}
170. 	return ""
171. }
172. 
173. // recentMessages returns the last n user/assistant turns of a stored
174. // transcript, each truncated, one per line, for the resume preamble. It reads
175. // the normalized shape; a transcript stored raw before normalization (an older
176. // checkpoint) falls back to the Claude-native reader so old sessions still
177. // resume.
178. func recentMessages(transcript []byte, n int) string {
179. 	if !looksNormalized(transcript) {
180. 		return recentMessagesNative(transcript, n)
181. 	}
182. 	var msgs []string
183. 	sc := bufio.NewScanner(bytes.NewReader(transcript))
184. 	sc.Buffer(make([]byte, 0, 64<<10), maxTranscriptLine)
185. 	for sc.Scan() {
186. 		line := bytes.TrimSpace(sc.Bytes())
187. 		if len(line) == 0 {
188. 			continue
189. 		}
190. 		var m Message
191. 		if json.Unmarshal(line, &m) != nil {
192. 			continue
193. 		}
194. 		if m.Role != "user" && m.Role != "assistant" {
195. 			continue
196. 		}
197. 		text := strings.TrimSpace(m.Content)
198. 		if text == "" || isWrapper(text) {
199. 			continue
200. 		}
201. 		if len(text) > 500 {
202. 			text = text[:500] + "…"
203. 		}
204. 		msgs = append(msgs, m.Role+": "+text)
205. 	}
206. 	if len(msgs) > n {
207. 		msgs = msgs[len(msgs)-n:]
208. 	}
209. 	return strings.Join(msgs, "\n")
210. }
211. 
212. // recentMessagesNative reads the last n user/assistant turns from a raw Claude
213. // Code transcript, for checkpoints recorded before transcripts were normalized.
214. func recentMessagesNative(transcript []byte, n int) string {
215. 	sc := bufio.NewScanner(bytes.NewReader(transcript))
216. 	sc.Buffer(make([]byte, 0, 64<<10), maxTranscriptLine)
217. 	var msgs []string
218. 	for sc.Scan() {
219. 		var line struct {
220. 			Type    string `json:"type"`
221. 			IsMeta  bool   `json:"isMeta"`
222. 			Message struct {
223. 				Content json.RawMessage `json:"content"`
224. 			} `json:"message"`
225. 		}
226. 		if err := json.Unmarshal(sc.Bytes(), &line); err != nil {
227. 			continue
228. 		}
229. 		if line.IsMeta || (line.Type != "user" && line.Type != "assistant") {
230. 			continue
231. 		}
232. 		text := strings.TrimSpace(contentText(line.Message.Content))
233. 		if text == "" || isWrapper(text) {
234. 			continue
235. 		}
236. 		if len(text) > 500 {
237. 			text = text[:500] + "…"
238. 		}
239. 		msgs = append(msgs, line.Type+": "+text)
240. 	}
241. 	if len(msgs) > n {
242. 		msgs = msgs[len(msgs)-n:]
243. 	}
244. 	return strings.Join(msgs, "\n")
245. }
246. 
247. // parseRFC3339 parses an RFC3339 (optionally nano) timestamp, returning the
248. // zero time when the string is empty or unparseable — a missing timestamp is a
249. // display detail, never a reason to drop a turn.
250. func parseRFC3339(s string) time.Time {
251. 	if s == "" {
252. 		return time.Time{}
253. 	}
254. 	if t, err := time.Parse(time.RFC3339Nano, s); err == nil {
255. 		return t
256. 	}
257. 	if t, err := time.Parse(time.RFC3339, s); err == nil {
258. 		return t
259. 	}
260. 	return time.Time{}
261. }
262. 
263. // parseEpochOrRFC3339 parses a timestamp that may be epoch milliseconds (a JSON
264. // number) or an RFC3339 string, returning the zero time when neither parses.
265. func parseEpochOrRFC3339(raw json.RawMessage) time.Time {
266. 	raw = json.RawMessage(bytes.TrimSpace(raw))
267. 	if len(raw) == 0 {
268. 		return time.Time{}
269. 	}
270. 	if raw[0] == '"' {
271. 		var s string
272. 		if json.Unmarshal(raw, &s) == nil {
273. 			return parseRFC3339(s)
274. 		}
275. 		return time.Time{}
276. 	}
277. 	var ms int64
278. 	if json.Unmarshal(raw, &ms) == nil && ms > 0 {
279. 		return time.UnixMilli(ms).UTC()
280. 	}
281. 	return time.Time{}
282. }
283. 
284. // RenderTranscript formats a stored transcript for display: one block per
285. // user/assistant turn, header then indented content, identical regardless of
286. // which agent produced it. A transcript stored raw before normalization (an
287. // older checkpoint) is returned as-is, so read-back never breaks.
288. func RenderTranscript(stored []byte) string {
289. 	if !looksNormalized(stored) {
290. 		return string(stored)
291. 	}
292. 	var b strings.Builder
293. 	sc := bufio.NewScanner(bytes.NewReader(stored))
294. 	sc.Buffer(make([]byte, 0, 64<<10), maxTranscriptLine)
295. 	for sc.Scan() {
296. 		line := bytes.TrimSpace(sc.Bytes())
297. 		if len(line) == 0 {
298. 			continue
299. 		}
300. 		var m Message
301. 		if json.Unmarshal(line, &m) != nil {
302. 			continue
303. 		}
304. 		content := strings.TrimRight(m.Content, "\n")
305. 		if m.Role == "" || strings.TrimSpace(content) == "" {
306. 			continue
307. 		}
308. 		b.WriteString(m.Role)
309. 		if !m.Timestamp.IsZero() {
310. 			b.WriteString("  ")
311. 			b.WriteString(m.Timestamp.Local().Format("2006-01-02 15:04:05"))
312. 		}
313. 		b.WriteByte('\n')
314. 		for l := range strings.SplitSeq(content, "\n") {
315. 			b.WriteString("  ")
316. 			b.WriteString(l)
317. 			b.WriteByte('\n')
318. 		}
319. 		b.WriteByte('\n')
320. 	}
321. 	return b.String()
322. }
323. 
324. // contextBlock builds a case-insensitive, DOTALL pattern matching a balanced
325. // XML-ish block <name …>…</name> (RE2 has no backreferences, so the tag name
326. // is fixed per pattern).
327. func contextBlock(name string) *regexp.Regexp {
328. 	return regexp.MustCompile(`(?is)<` + name + `\b[^>]*>.*?</` + name + `>`)
329. }
330. 
331. // intentStrippers are the editor/IDE and Claude Code context wrappers that get
332. // injected around or alongside a typed prompt. They carry machine context, not
333. // what the human asked, so sanitizeIntent removes them from the extracted
334. // intent — for live recording and import alike.
335. var intentStrippers = []*regexp.Regexp{
336. 	contextBlock("system-reminder"),
337. 	contextBlock("context"),
338. 	contextBlock("command-name"),
339. 	contextBlock("command-message"),
340. 	contextBlock("command-args"),
341. 	contextBlock("local-command-stdout"),
342. 	contextBlock("local-command-stderr"),
343. 	// IDE integration blocks: <ide_selection>…</ide_selection>, <ide-opened-
344. 	// file>…, and the like — any ide_/ide- prefixed tag.
345. 	regexp.MustCompile(
346. 		`(?is)<ide[_-][a-z0-9_-]*\b[^>]*>.*?</ide[_-][a-z0-9_-]*>`,
347. 	),
348. }
349. 
350. // sanitizeIntent strips injected context/IDE wrappers from an extracted intent
351. // so titles and search show what the human actually typed, then trims the
352. // remainder. Shared by live recording and import: one extractor, one behavior.
353. func sanitizeIntent(text string) string {
354. 	for _, re := range intentStrippers {
355. 		text = re.ReplaceAllString(text, "")
356. 	}
357. 	return strings.TrimSpace(text)
358. }
359. 
360. // isWrapper reports whether a user entry is agent plumbing (slash command
361. // expansion, command output echo) rather than a typed prompt.
362. func isWrapper(text string) bool {
363. 	for _, p := range []string{
364. 		"<command-name>", "<local-command-stdout>", "<system-reminder>",
365. 	} {
366. 		if strings.HasPrefix(text, p) {
367. 			return true
368. 		}
369. 	}
370. 	return false
371. }
372. 
373. // contentText flattens a message content field, which is either a plain string
374. // or an array of typed blocks, into its text. Non-text blocks (tool results,
375. // images) contribute nothing. Shared by the agents whose native content field
376. // uses the Anthropic block shape (Claude Code, Cursor).
377. func contentText(raw json.RawMessage) string {
378. 	if len(raw) == 0 {
379. 		return ""
380. 	}
381. 	var s string
382. 	if err := json.Unmarshal(raw, &s); err == nil {
383. 		return s
384. 	}
385. 	var blocks []struct {
386. 		Type string `json:"type"`
387. 		Text string `json:"text"`
388. 	}
389. 	if err := json.Unmarshal(raw, &blocks); err != nil {
390. 		return ""
391. 	}
392. 	var b strings.Builder
393. 	for _, blk := range blocks {
394. 		if blk.Type == "text" {
395. 			b.WriteString(blk.Text)
396. 		}
397. 	}
398. 	return b.String()
399. }
400.

