91. // info/exclude (best-effort) so recording never dirties git status. finish
92. // is an optional extra mutation of the top-level document (e.g. Gemini's
93. // hooksConfig.enabled).
94. func installNested(
95. 	f configFile,
96. 	repoDir, tool, wasaExe string,
97. 	events []hookEvent,
98. 	entry entryMaker,
99. 	finish func(top map[string]json.RawMessage),
100. ) error {
101. 	if entry == nil {
102. 		entry = plainEntry
103. 	}
104. 	top, hooks, err := loadNested(f.path)
105. 	if err != nil {
106. 		return err
107. 	}
108. 	changed := false
109. 	for _, event := range events {
110. 		if hasRecordHook(hooks[event.name]) {
111. 			continue
112. 		}
113. 		hooks[event.name] = append(hooks[event.name], settingsHookMatcher{
114. 			Hooks: []settingsHookEntry{
115. 				entry(HookCommand(wasaExe, tool, event.end)),
116. 			},
117. 		})
118. 		changed = true
119. 	}
120. 	if changed {
121. 		rawHooks, err := json.Marshal(hooks)
122. 		if err != nil {
123. 			return err
124. 		}
125. 		top["hooks"] = rawHooks
126. 		if finish != nil {
127. 			finish(top)
128. 		}
129. 		if err := writeJSONFile(f.path, top); err != nil {
130. 			return err
131. 		}
132. 	}
133. 	ensureExcluded(repoDir, f.exclude)
