137. // removeNested strips wasa's recording entries from a Claude-style settings
138. // file, leaving every other setting and hook in place. ownedTop lists
139. // top-level keys the installer added besides hooks; they are dropped when
140. // they are all that remains, and the file is deleted when nothing else is
141. // left. A missing file is a no-op.
142. func removeNested(f configFile, ownedTop []string) error {
143. 	if _, err := os.Stat(f.path); os.IsNotExist(err) {
144. 		return nil
145. 	}
146. 	top, hooks, err := loadNested(f.path)
147. 	if err != nil {
148. 		return err
149. 	}
150. 	changed := false
151. 	for event, matchers := range hooks {
152. 		var kept []settingsHookMatcher
153. 		for _, m := range matchers {
154. 			if matcherIsRecordHook(m) {
155. 				changed = true
156. 				continue
157. 			}
158. 			kept = append(kept, m)
159. 		}
160. 		if len(kept) == 0 {
161. 			delete(hooks, event)
162. 		} else {
163. 			hooks[event] = kept
164. 		}
165. 	}
166. 	if !changed {
167. 		return nil
168. 	}
169. 	if len(hooks) == 0 {
170. 		delete(top, "hooks")
171. 	} else {
172. 		rawHooks, err := json.Marshal(hooks)
173. 		if err != nil {
174. 			return err
175. 		}
176. 		top["hooks"] = rawHooks
177. 	}
