189. 	_, hooks, err := loadNested(f.path)
190. 	if err != nil {
191. 		return false
192. 	}
193. 	for _, matchers := range hooks {
194. 		if hasRecordHook(matchers) {
195. 			return true
196. 		}
197. 	}
198. 	return false
