201. // installFlat writes wasa's recording hooks in the flat version-1 shape
202. // Copilot and Cursor discover: {"version":1,"hooks":{"<event>":[<entry>]}}.
203. // wasa owns the whole file (it is named after wasa or lives in a discovery
204. // directory), so install rewrites it and remove deletes it; a foreign file
205. // without wasa's marker is left untouched and reported.
206. func installFlat(
207. 	f configFile,
208. 	repoDir, tool, wasaExe string,
209. 	events []hookEvent,
210. 	entry entryMaker,
211. ) error {
212. 	if data, err := os.ReadFile(f.path); err == nil &&
213. 		!strings.Contains(string(data), hookMarker) {
214. 		return fmt.Errorf(
215. 			"%s exists and is not wasa's; not overwriting",
216. 			f.path,
217. 		)
218. 	}
219. 	hooks := map[string][]settingsHookEntry{}
220. 	for _, event := range events {
221. 		hooks[event.name] = []settingsHookEntry{
222. 			entry(HookCommand(wasaExe, tool, event.end)),
223. 		}
224. 	}
225. 	rawHooks, err := json.Marshal(hooks)
226. 	if err != nil {
227. 		return err
228. 	}
229. 	top := map[string]json.RawMessage{
230. 		"version": json.RawMessage("1"),
231. 		"hooks":   rawHooks,
232. 	}
233. 	if err := writeJSONFile(f.path, top); err != nil {
234. 		return err
235. 	}
236. 	ensureExcluded(repoDir, f.exclude)
237. 	return nil
238. }
239. 
240. func removeFlat(f configFile) error {
241. 	data, err := os.ReadFile(f.path)
242. 	if os.IsNotExist(err) {
243. 		return nil
244. 	}
245. 	if err != nil {
246. 		return err
247. 	}
248. 	if !strings.Contains(string(data), hookMarker) {
249. 		return nil
250. 	}
251. 	if err := os.Remove(f.path); err != nil {
252. 		return err
253. 	}
254. 	_ = os.Remove(filepath.Dir(f.path))
255. 	return nil
256. }
257. 
258. func flatInstalled(f configFile) bool {
259. 	data, err := os.ReadFile(f.path)
260. 	return err == nil && strings.Contains(string(data), hookMarker)
261. }
262. 
263. // copilotHookFile is wasa's recorder hook in the repository's .github/hooks
264. // directory — the repo-level hook location Copilot reads (alongside any other
265. // .github/hooks/*.json). The file is wasa-owned and distinctly named, so
266. // installFlat rewrites it, removeFlat deletes it, and a foreign file without
267. // wasa's marker is left untouched. It is added to info/exclude like every other
268. // recorder config so recording never dirties git status.
269. func copilotHookFile(dir string) configFile {
270. 	return settingsFile(dir, filepath.Join(".github", "hooks"), "wasa.json")
271. }
272. 
273. // copilotEntry is a Copilot repo-hook entry: {"type":"command","command":...}.
274. func copilotEntry(command string) settingsHookEntry {
275. 	return settingsHookEntry{Type: "command", Command: command}
276. }
277. 
278. // codexFeatureFlag is the config.toml content Codex needs before it runs
279. // hooks at all. wasa carries no TOML parser, so it only creates the file
280. // when missing and only deletes it when unchanged; an existing config.toml
281. // the user owns is never edited.
282. const codexFeatureFlag = "[features]\nhooks = true\n"
283. 
284. func codexConfigPath(dir string) string {
285. 	return filepath.Join(dir, ".codex", "config.toml")
286. }
287. 
288. func ensureCodexFeature(dir string) error {
289. 	path := codexConfigPath(dir)
290. 	data, err := os.ReadFile(path)
291. 	switch {
292. 	case os.IsNotExist(err):
293. 		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
294. 			return err
295. 		}
296. 		if err := os.WriteFile(
297. 			path,
298. 			[]byte(codexFeatureFlag),
299. 			0o644,
300. 		); err != nil {
301. 			return err
302. 		}
303. 		ensureExcluded(dir, ".codex/config.toml")
304. 		return nil
305. 	case err != nil:
306. 		return err
307. 	case strings.Contains(string(data), "hooks = true"),
308. 		strings.Contains(string(data), "hooks=true"):
309. 		return nil
310. 	default:
311. 		return fmt.Errorf(
312. 			"codex hooks are disabled: add \"[features]\\nhooks = true\" to %s",
313. 			path,
314. 		)
315. 	}
316. }
317. 
318. func removeCodexFeature(dir string) {
319. 	path := codexConfigPath(dir)
320. 	if data, err := os.ReadFile(path); err == nil &&
321. 		string(data) == codexFeatureFlag {
322. 		_ = os.Remove(path)
323. 		_ = os.Remove(filepath.Dir(path))
324. 	}
325. }
326. 
327. // enableGeminiHooks sets hooksConfig.enabled, without which Gemini ignores
328. // the hooks section entirely.
329. func enableGeminiHooks(top map[string]json.RawMessage) {
330. 	cfg := map[string]json.RawMessage{}
331. 	if raw, ok := top["hooksConfig"]; ok {
332. 		_ = json.Unmarshal(raw, &cfg)
333. 	}
334. 	cfg["enabled"] = json.RawMessage("true")
335. 	if raw, err := json.Marshal(cfg); err == nil {
336. 		top["hooksConfig"] = raw
337. 	}
338. }
339. 
340. // loadNested parses a settings file into its top-level raw fields and its
341. // decoded hooks map. A missing or empty file yields empty maps.
342. func loadNested(path string) (
343. 	map[string]json.RawMessage, map[string][]settingsHookMatcher, error,
344. ) {
345. 	top := map[string]json.RawMessage{}
346. 	data, err := os.ReadFile(path)
347. 	switch {
348. 	case os.IsNotExist(err):
349. 	case err != nil:
350. 		return nil, nil, err
351. 	case len(strings.TrimSpace(string(data))) > 0:
352. 		if err := json.Unmarshal(data, &top); err != nil {
353. 			return nil, nil, fmt.Errorf(
354. 				"settings %s is not valid JSON; leaving it untouched: %w",
355. 				path, err,
356. 			)
357. 		}
358. 	}
359. 	hooks := map[string][]settingsHookMatcher{}
360. 	if raw, ok := top["hooks"]; ok {
361. 		if err := json.Unmarshal(raw, &hooks); err != nil {
362. 			return nil, nil, fmt.Errorf(
363. 				"settings %s has malformed hooks: %w", path, err,
364. 			)
365. 		}
366. 	}
367. 	return top, hooks, nil
368. }
369. 
370. // writeJSONFile re-encodes a settings document atomically.
371. func writeJSONFile(path string, top map[string]json.RawMessage) error {
372. 	out, err := json.MarshalIndent(top, "", "  ")
373. 	if err != nil {
374. 		return err
375. 	}
376. 	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
377. 		return err
378. 	}
379. 	tmp, err := os.CreateTemp(filepath.Dir(path), ".wasa-tmp-*")
380. 	if err != nil {
381. 		return err
382. 	}
383. 	tmpName := tmp.Name()
384. 	if _, err := tmp.Write(out); err != nil {
385. 		tmp.Close()
386. 		os.Remove(tmpName)
387. 		return err
388. 	}
389. 	if err := tmp.Close(); err != nil {
390. 		os.Remove(tmpName)
391. 		return err
392. 	}
393. 	return os.Rename(tmpName, path)
394. }
395. 
396. func onlyOwnedKeys(top map[string]json.RawMessage, owned []string) bool {
397. 	for key := range top {
398. 		if !slices.Contains(owned, key) {
399. 			return false
400. 		}
401. 	}
402. 	return true
403. }
404. 
405. func hasRecordHook(matchers []settingsHookMatcher) bool {
406. 	return slices.ContainsFunc(matchers, matcherIsRecordHook)
407. }
408. 
409. func matcherIsRecordHook(m settingsHookMatcher) bool {
410. 	for _, h := range m.Hooks {
411. 		if strings.Contains(h.Command, hookMarker) ||
412. 			strings.Contains(h.Bash, hookMarker) {
413. 			return true
414. 		}
415. 	}
416. 	return false
417. }
418. 
419. // ensureExcluded appends entry (a repo-root-relative path) to the
420. // repository's shared info/exclude when missing, so installed hook
421. // configuration never dirties git status or blocks a clean worktree
422. // removal. Tracked files are unaffected by exclude; a repository that
423. // commits its agent settings keeps full control of them. Best-effort: any
424. // failure is ignored, costing only an untracked-file line in git status.
425. func ensureExcluded(dir, entry string) {
426. 	commonDir, err := gitIn(
427. 		dir, nil, "rev-parse", "--path-format=absolute", "--git-common-dir",
428. 	)
429. 	if err != nil || commonDir == "" {
430. 		return
431. 	}
432. 	path := filepath.Join(commonDir, "info", "exclude")
433. 	data, _ := os.ReadFile(path)
434. 	for line := range strings.SplitSeq(string(data), "\n") {
435. 		if strings.TrimSpace(line) == entry {
436. 			return
437. 		}
438. 	}
439. 	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
440. 		return
441. 	}
442. 	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
443. 	if err != nil {
444. 		return
445. 	}
446. 	defer f.Close()
447. 	prefix := ""
448. 	if len(data) > 0 && !strings.HasSuffix(string(data), "\n") {
449. 		prefix = "\n"
450. 	}
451. 	fmt.Fprintf(f, "%s%s\n", prefix, entry)
452. }
453.

