1. package record
2. 
3. import (
4. 	"fmt"
5. 	"log"
6. 	"os"
7. 	"os/exec"
8. 	"path/filepath"
9. 	"strings"
10. 	"time"
11. 
12. 	"github.com/joakimcarlsson/wasa-cli/internal/registry"
13. 	"github.com/joakimcarlsson/wasa-cli/internal/worktree"
14. )
15. 
16. // commitBurstLimit caps per-commit checkpoints written from one detection.
17. // An agent commits one at a time, but a pull or rebase can make hundreds of
18. // commits appear at once; those collapse into a single checkpoint.
19. const commitBurstLimit = 10
20. 
21. // Event is one agent hook invocation, normalized by the CLI handler.
22. type Event struct {
23. 	// Agent is the reporting agent's recording tool name, e.g. "claude".
24. 	Agent string
25. 	// AgentSessionID is the agent's own session identifier, used as the
26. 	// recorded session id when no wasa session surrounds it and to locate
27. 	// the transcript when no payload named it.
28. 	AgentSessionID string
29. 	// TranscriptPath is where the agent keeps the session transcript.
30. 	TranscriptPath string
31. 	// Prompt is the user prompt carried by prompt-bearing hook events; the
32. 	// first one seen becomes the session intent.
33. 	Prompt string
34. 	// Dir is the directory the agent runs in.
35. 	Dir string
36. 	// WasaSession is the surrounding wasa session id; empty marks an
37. 	// unmanaged session recorded via repo-level hooks.
38. 	WasaSession string
39. 	// End marks the agent's session-end event, set by the --event end flag
40. 	// the installer wrote on that hook entry.
41. 	End bool
42. }
43. 
44. // HandleEvent advances a session's recording from one agent hook event: it
45. // tracks the transcript location and intent, writes a commit-linked
46. // checkpoint for every commit that landed since the last event, and closes
47. // an unmanaged session's record on the agent's session-end event (a managed
48. // session is closed by the finish flow instead). It never returns anything:
49. // the hook contract is fire-and-forget, so every failure is a silent no-op.
50. func HandleEvent(home string, ev Event) {
51. 	if _, ok := recorderFor(ev.Agent); !ok || ev.Dir == "" {
52. 		return
53. 	}
54. 	repoDir, err := worktree.Toplevel(ev.Dir)
55. 	if err != nil {
56. 		return
57. 	}
58. 	sid := ev.WasaSession
59. 	if sid == "" {
60. 		sid = ev.AgentSessionID
61. 	}
62. 	if sid == "" {
63. 		return
64. 	}
65. 
66. 	st, ok := loadState(home, sid)
67. 	if !ok {
68. 		st = newState(home, sid, repoDir, ev)
69. 	}
70. 	if ev.AgentSessionID != "" {
71. 		st.AgentSessionID = ev.AgentSessionID
72. 	}
73. 	if ev.TranscriptPath != "" {
74. 		st.TranscriptPath = ev.TranscriptPath
75. 	}
76. 	if st.TranscriptPath == "" {
77. 		st.TranscriptPath = fallbackTranscript(
78. 			ev.Agent, ev.AgentSessionID, repoDir,
79. 		)
80. 	}
81. 	if st.Intent == "" {
82. 		st.Intent = strings.TrimSpace(ev.Prompt)
83. 	}
84. 	if st.Intent == "" {
85. 		transcript, _ := os.ReadFile(st.TranscriptPath)
86. 		st.Intent = intentFrom(st.Agent, transcript)
87. 	}
88. 
89. 	if head := headSHA(repoDir); head != "" && head != st.LastHead {
90. 		st = checkpointNewCommits(repoDir, st, head)
91. 	}
92. 
93. 	_ = saveState(home, st)
94. 	if ev.End && st.Unmanaged {
95. 		startFinalize(home, sid)
96. 	}
97. }
98. 
99. // startFinalize writes an unmanaged session's closing checkpoint. In
100. // production it spawns a detached child (spawnFinalize) so that an agent
101. // cancelling its SessionEnd hook — as headless Claude Code does on exit —
102. // cannot abort the write; tests override it to run Finalize inline.
103. var startFinalize = spawnFinalize
104. 
105. // spawnFinalize launches "wasa record-finalize --session <sid>" in its own
106. // session, so the closing checkpoint is written off the hook's lifecycle and
107. // survives the hook process being killed. The child re-derives $WASA_HOME from
108. // the inherited environment. Best-effort: an exec failure leaves the state on
109. // disk for the next run to finalize.
110. func spawnFinalize(_, sid string) {
111. 	exe, err := os.Executable()
112. 	if err != nil {
113. 		return
114. 	}
115. 	cmd := exec.Command(exe, "record-finalize", "--session", sid)
116. 	cmd.Env = os.Environ()
117. 	detach(cmd)
118. 	if cmd.Start() == nil {
119. 		_ = cmd.Process.Release()
120. 	}
121. }
122. 
123. // Finalize writes a session's closing checkpoint from its persisted recording
124. // state: any commits since the last event, the final transcript, the commit
125. // list and the finish timestamp, then drops the state. It is what the detached
